var e=JSON.parse(`[{"id":"L2_1","type":"subtitle","speaker":null,"text":{"KOREA":"사흘 전","JPN":"三日前","ENG":"Three days earlier","TWN":"三天前","SCN":"三天前","DEU":"Three days earlier","FRA":"Three days earlier"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L3_1","type":"subtitle","speaker":null,"text":{"KOREA":"1888년 10월 22일 런던, <color=#ffd34c>베이커 가 211번지</color>","JPN":"1888年10月22日　ロンドン、<color=#ffd34c>ベーカー街211番地</color>","ENG":"October 22, 1888, London, <color=#ffd34c>211 Baker St.</color>","TWN":"1888年10月22日 倫敦, <color=#ffd34c>貝克街211號</color>","SCN":"1888年10月22日 伦敦, <color=#ffd34c>贝克街211号</color>","DEU":"October 22, 1888, London, <color=#ffd34c>211 Baker St.</color>","FRA":"October 22, 1888, London, <color=#ffd34c>211 Baker St.</color>"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"애버라인, 문틈에 무슨 편지가 껴있던데요?","JPN":"アバーライン、ドアの隙間に手紙が挟んでありましたよ？","ENG":"Abberline, there's some kind of letter wedged in the door gap.","TWN":"艾伯林，門縫裡夾著一封信。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"편지라고? 그럴 리가 없지 않나?","JPN":"手紙？　そんなはずあるまい。","ENG":"A letter? That's impossible.","TWN":"信？怎麼可能有信呢？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L10_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이 아지트는 인식 저해가 걸려있다네. 평범한 사람은 인식할 수 없지.","JPN":"このアジトには認識阻害措置がされている。普通の人間は認識できない。","ENG":"This hideout is with a Curio to hinder people's perception. An ordinary person can't recognize it.","TWN":"這個安全屋有認知干擾。普通人是無法察覺的。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"더욱이 나한테 편지 같은 걸 보낼 사람도 없고 말이야.","JPN":"それに私に手紙を送るような人もいないしな。","ENG":"Furthermore, there is no one who would send me any letters.","TWN":"而且也沒有人會給我寄信。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"글쎄요, 당신 인간관계 같은 건 전혀 궁금하지 않거든요?","JPN":"さあ、あなたの人間関係とか全然興味ありませんけどね。","ENG":"Well, I'm not curious about your personal relationships.","TWN":"哼，我對你的社交關係一點都不感興趣。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"자, 보세요. 정말로 편지가 있었다고요.","JPN":"はい、どうぞ。本当に手紙があったんです。","ENG":"But look. There really is a letter here for you.","TWN":"看吧，真的有信。"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"잠깐, 그 편지는……?","JPN":"待て、その手紙は……？","ENG":"Wait, this letter…?","TWN":"等等，那封信是……？"},"stage":{"bg":"ROOM_03","slots":{"L":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"C":null,"R":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L20_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"어디보자. 친애하는 벗에게…….","JPN":"どれどれ。親愛なる友へ……","ENG":"Let’s see here. To my dear friend...","TWN":"我看看——致我親愛的朋友……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"음? 이거 수취인이 당신이 아닌데요? 뭔가 잘못 온 편지가…… ","JPN":"うん？　これ、あなた宛てじゃありませんね？　どうやら住所が…… ","ENG":"Hmm? This wasn't sent to you. Guess it's a delivery mistake–","TWN":"嗯？這封信的收件人不是你啊？好像是寄錯的信……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"엇!?","JPN":"あっ！？","ENG":"Huh?","TWN":"呃？！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"크흠, 정정하지.","JPN":"コホン、訂正しよう。","ENG":"Ahem, I take it back.","TWN":"咳咳，我收回前言。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"이건 나한테 온 편지가 맞아. 그리고 무척 오랫동안 기다리고 있었던 편지지.","JPN":"これは確かに私宛ての手紙だ。それも、長い間待ち望んでいた、な。","ENG":"This letter is for me. And it's a letter that I've been anticipating for a very long time.","TWN":"這是給我的信。也是我等待了很久的信。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"흥……!","JPN":"ふんっ……！","ENG":"Hmph...!","TWN":"哼……！"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"심야가 될 때까지 안락의자에 틀어박혀 꿈쩍도 안 하더니, 이럴 때는 재빠르시군요.","JPN":"深夜になるまでアームチェアにずっと座ってビクともしなかったのに、こんな時は素早いんですね。","ENG":"You never get out of that armchair until it's late at night. But you're quick to snatch that away from me.","TWN":"一直窩在安樂椅上到深夜都不動，這種時候倒是挺快的嘛。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"무슨 팬레터라도 되나요? 누구 편지인데 그래요?","JPN":"ファンレターか何かですか？　誰からの手紙なんですか？","ENG":"A fan letter of yours? Who's it from?","TWN":"是誰的信啊？粉絲信嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"사흘 뒤라…….","JPN":"三日後か……","ENG":"In three days...","TWN":"三天後啊……"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"그래, 결행일은 사흘 뒤인가?","JPN":"そうか、決行する日は三日後なのか。","ENG":"Right, so the day is going to be in three days.","TWN":"好，行動日是三天後嗎？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L33_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"결행일?","JPN":"決行する日？","ENG":"The day?","TWN":"行動日？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"스완. 지금부터 내가 하는 이야기를 잘 기억하게.","JPN":"スワン。今から私の言うことをしっかりと覚えてほしい。","ENG":"Swan. Do not forget what I'm about to tell you right now.","TWN":"史旺。從現在開始，你要好好記住我說的話。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ABBERLINE_SWANSONG_NPC_NULL","text":{"KOREA":"무척 중요한 이야기니까 말이지.","JPN":"とても大事な話だからな。","ENG":"I can't stress how important it is.","TWN":"因為這是非常重要的事情。"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"ABBERLINE_SWANSONG_NPC_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"SWAN_SWANSONG_NPC_NULL","text":{"KOREA":"중요한 이야기라고요?","JPN":"大事な話……ですか？","ENG":"Important?","TWN":"重要的事情？"},"stage":{"bg":"ROOM_03","slots":{"L":null,"C":{"char_id":"SWAN_SWANSONG_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L43_1","type":"subtitle","speaker":null,"text":{"KOREA":"L44_1","JPN":"L44_1","ENG":"L44_1","TWN":"L44_1","SCN":"L44_1","DEU":"L44_1","FRA":"L44_1"},"stage":{"bg":"BLACK","slots":{"L":null,"C":null,"R":null}}}]`);export{e as default};